+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        write!(
+            f,
+            "PrivacyLearningContract(id={}, epoch={}, zone={}, schema_v={}, dp={}/{})",
+            self.contract_id,
+            self.epoch,
+            self.zone,
+            self.feature_schema.version,
+            self.dp_budget.composition_method,
+            self.dp_budget.epsilon_per_epoch_millionths,
+        )
+    }
+}
